    def get_handler(self, type):
        if type == 'deposit':
            return self.handle_deposit
        elif type == 'withdraw':
            return self.handle_withdraw
        else:
            raise Exception(f'Unknown transaction type: {type}')

    def handle_deposit(self, transaction):
        print(f"Depositing {transaction['amount']} to account {transaction['account_id']}")

    def handle_withdraw(self, transaction):
        print(f"Withdrawing {transaction['amount']} from account {transaction['account_id']}")

